function renderSoundToggle(): string {
  const muted = isSfxMuted();
  return `<button type="button" class="sound-toggle${muted ? ' muted' : ''}" id="btn-sound" aria-label="${muted ? 'Включить звук' : 'Выключить звук'}" title="${muted ? 'Звук выкл' : 'Звук вкл'}">${soundToggleIcon(muted)}<span class="sound-toggle-label">${muted ? 'Выкл' : 'Звук'}</span></button>`;
}

function wireSoundToggle(): void {
  ensureSfxGestureUnlock();
  const btn = document.getElementById('btn-sound');
  if (!btn) return;
  btn.addEventListener('click', () => {
    unlockSfx();
    const muted = toggleSfxMuted();
    btn.classList.toggle('muted', muted);
    btn.setAttribute('aria-label', muted ? 'Включить звук' : 'Выключить звук');
    btn.setAttribute('title', muted ? 'Звук выкл' : 'Звук вкл');
    btn.innerHTML = `${soundToggleIcon(muted)}<span class="sound-toggle-label">${muted ? 'Выкл' : 'Звук'}</span>`;
    if (!muted) void playRepBeep();
  });
}

function currentFoe(): Foe {
  if (!activeLevel) throw new Error('No active level');
  return getFoe(activeLevel, foeIndex);
}

function isCameraAlive(): boolean {
  return Boolean(stream && stream.getVideoTracks().some((t) => t.readyState === 'live'));
}

async function bindCameraToVideo(video: HTMLVideoElement): Promise<void> {
  if (!stream) throw new Error('Нет потока камеры');
  video.setAttribute('playsinline', '');
  video.setAttribute('webkit-playsinline', '');
  video.muted = true;
  video.defaultMuted = true;
  video.playsInline = true;
  video.autoplay = true;
  // Always re-assign so the element picks up the live track after remount.
  video.srcObject = null;
  video.srcObject = stream;
  bindVideoSqueeze(video);

  // Never hang the UI on play() — some mobile browsers leave the promise pending.
  try {
    const playing = video.play();
    if (playing) {
      await Promise.race([
        playing.then(() => undefined).catch((err: unknown) => {
          const name = err instanceof DOMException ? err.name : '';
          if (name !== 'AbortError' && name !== 'NotAllowedError') throw err;
        }),
        new Promise<void>((resolve) => {
          window.setTimeout(resolve, 600);
        })
      ]);
    }
  } catch (err) {
    const name = err instanceof DOMException ? err.name : '';
    if (name !== 'AbortError' && name !== 'NotAllowedError') throw err;
  }
  bindVideoSqueeze(video);
}

function dismissBootOverlay(): void {
  document.getElementById('boot-overlay')?.remove();
}

function setBootMsg(text: string): void {
  const bootMsg = document.getElementById('boot-msg');
  if (bootMsg) bootMsg.textContent = text;
}

function stopDetectorOnly(): void {
  detector?.stop();
  detector = null;
}

function clearWaveTimer(): void {
  if (waveAdvanceTimer) {
    window.clearTimeout(waveAdvanceTimer);
    waveAdvanceTimer = 0;
  }
}

function clearChallengeTimer(): void {
  if (challengeTimerId) {
    window.clearInterval(challengeTimerId);
    challengeTimerId = 0;
  }
}

function goHome(): void {
  clearChallengeTimer();
  stopDetectorOnly();
  unbindVideoSqueeze();
  screen = 'home';
  activeLevel = null;
  activeChallenge = null;
  playMode = 'arena';
  foeIndex = 0;
  damage = 0;
  render();
}

async function requestCameraAccess(opts?: { silent?: boolean }): Promise<boolean> {
  const silent = Boolean(opts?.silent);
  if (!silent) {
    cameraBusy = true;
    cameraError = '';
    render();
  }

  try {
    if (!window.isSecureContext) {
      throw new Error('Нужен HTTPS или localhost. Открой адрес https://… (не http://).');
    }
    if (!navigator.mediaDevices?.getUserMedia) {
      throw new Error('Этот браузер не умеет открывать камеру.');
    }
    if (stream) {
      stream.getTracks().forEach((t) => t.stop());
      stream = null;
    }
    stream = await navigator.mediaDevices.getUserMedia(VIDEO_CONSTRAINTS);
    cameraReady = true;
    cameraError = '';
    void RepDetector.warmUp().catch(() => undefined);
    return true;
  } catch (err) {
    cameraReady = false;
    if (silent) return false;
    const name = err instanceof DOMException ? err.name : '';
    const message = err instanceof Error ? err.message : String(err);
    if (name === 'NotAllowedError' || name === 'PermissionDeniedError') {
      cameraError =
        'Доступ к камере запрещён. В Chrome: замок у адреса → Камера → Разрешить, затем нажми кнопку снова.';
    } else if (name === 'NotFoundError' || name === 'DevicesNotFoundError') {
      cameraError = 'Камера не найдена на этом устройстве.';
    } else {
      cameraError = message;
    }
    return false;
  } finally {
    if (!silent) cameraBusy = false;
    if (screen === 'home') render();
  }
}

/** Если браузер уже выдал камеру — сразу ✓ без клика. */
async function tryAutoEnableCamera(): Promise<void> {
  if (cameraReady || !window.isSecureContext || !navigator.mediaDevices?.getUserMedia) return;
  try {
    const status = await navigator.permissions.query({
      name: 'camera' as PermissionName
    });
    if (status.state !== 'granted') return;
    await requestCameraAccess({ silent: true });
  } catch {
    /* Permissions API / camera не поддерживается — ждём ручной клик */
  }
}

function render(): void {
  clearWaveTimer();
  if (screen === 'home') {
    app.innerHTML = renderHome();
    bindHome();
    return;
  }
  if (screen === 'setup') {
    app.innerHTML = renderSetupShell();
    void startSetup();
    return;
  }
  if (screen === 'wave' && activeLevel) {
    app.innerHTML = renderWaveClear(activeLevel, currentFoe());
    bindWaveClear();
    return;
  }
  if (screen === 'victory' && activeLevel) {
    app.innerHTML = renderVictory(activeLevel);
    bindVictory();
    return;
  }
  if (screen === 'challengeResult' && activeChallenge) {
    app.innerHTML = renderChallengeResult(activeChallenge);
    bindChallengeResult();
    return;
  }
  if (screen === 'fight') {
    if (playMode === 'challenge' && activeChallenge) {
      app.innerHTML = renderChallengeFight(activeChallenge);
      void startChallengeFight(activeChallenge);
    } else if (activeLevel) {
      app.innerHTML = renderFightShell(activeLevel, currentFoe());
      void startFight(currentFoe());
    }
  }
}

