function bindHome(): void {
  document.getElementById('btn-camera')?.addEventListener('click', () => {
    void requestCameraAccess();
  });

  app.querySelectorAll<HTMLButtonElement>('[data-exercise]').forEach((btn) => {
    btn.addEventListener('click', () => {
      selectedExercise = btn.dataset.exercise as ExerciseId;
      render();
    });
  });

  app.querySelectorAll<HTMLButtonElement>('[data-tab]').forEach((btn) => {
    btn.addEventListener('click', () => {
      homeTab = btn.dataset.tab as HomeTab;
      render();
    });
  });

  app.querySelectorAll<HTMLButtonElement>('[data-level]').forEach((btn) => {
    btn.addEventListener('click', () => {
      if (!cameraReady) return;
      playMode = 'arena';
      activeLevel = getLevel(btn.dataset.level as LevelId);
      activeChallenge = null;
      foeIndex = 0;
      damage = 0;
      phase = 'unknown';
      poseFound = false;
      lastHint = '';
      setupReadySince = null;
      setupCountdownDone = false;
      setupCountdownSoundSec = null;
      screen = 'setup';
      render();
    });
  });

  app.querySelectorAll<HTMLButtonElement>('[data-challenge]').forEach((btn) => {
    btn.addEventListener('click', () => {
      if (!cameraReady) return;
      playMode = 'challenge';
      activeChallenge = getChallenge(btn.dataset.challenge as ChallengeId);
      activeLevel = null;
      foeIndex = 0;
      damage = 0;
      phase = 'unknown';
      poseFound = false;
      lastHint = '';
      setupReadySince = null;
      setupCountdownDone = false;
      setupCountdownSoundSec = null;
      challengeWon = false;
      screen = 'setup';
      render();
    });
  });
}

function setupTitle(): string {
  if (playMode === 'challenge' && activeChallenge) {
    return `${activeChallenge.emoji} ${activeChallenge.name}`;
  }
  if (activeLevel) return `${activeLevel.emoji} ${activeLevel.name}`;
  return 'Настройка';
}

function setupSubtitle(): string {
  if (playMode === 'challenge' && activeChallenge) {
    return `${activeChallenge.foeEmoji} ${activeChallenge.foeName} · ${activeChallenge.targetReps} пов. / ${activeChallenge.timeLimitSec} с`;
  }
  if (activeLevel) {
    const foe = currentFoe();
    return `Первый: ${foe.emoji} ${foe.name}`;
  }
  return '';
}

