function beginFightFromSetup(): void {
  if (setupCountdownDone) return;
  setupCountdownDone = true;
  if (setupCountdownSoundSec !== -1) {
    setupCountdownSoundSec = -1;
    void playCountdownGo();
  }
  stopDetectorOnly();
  damage = 0;
  phase = 'unknown';
  poseFound = false;
  lastHint = '';
  screen = 'fight';
  render();
}

function updateSetupUi(result: SetupResult): void {
  const now = Date.now();
  if (!result.ready) {
    setupReadySince = null;
    setupCountdownSoundSec = null;
  } else if (setupReadySince === null) setupReadySince = now;

  const elapsedSec = setupReadySince != null ? (now - setupReadySince) / 1000 : 0;
  const remaining =
    setupReadySince != null ? Math.max(0, Math.ceil(3 - elapsedSec)) : null;
  const locked = remaining === 0;

  const list = document.getElementById('setup-checks');
  const hint = document.getElementById('setup-hint');
  const cdLine = document.getElementById('setup-countdown');
  const cdOverlay = document.getElementById('setup-countdown-overlay');
  const cdBig = document.getElementById('setup-countdown-big');
  const cdRing = document.getElementById('setup-countdown-ring') as SVGCircleElement | null;
  const ringC = 2 * Math.PI * 52;

  if (list) {
    const missing = result.checks.filter((c) => !c.ok);
    const show = missing.length > 0 ? missing : result.checks;
    list.innerHTML = show
      .map(
        (c) =>
          `<li class="setup-check ${c.ok ? 'ok' : 'bad'}">${c.ok ? '✓' : '!'} ${c.label}</li>`
      )
      .join('');
    list.classList.toggle('setup-checks-missing', missing.length > 0);
  }

  if (remaining != null && remaining > 0) {
    const progressLeft = Math.max(0, Math.min(1, 1 - elapsedSec / 3));
    if (cdOverlay) cdOverlay.hidden = false;
    if (cdBig) {
      const next = String(remaining);
      if (cdBig.textContent !== next) {
        cdBig.textContent = next;
        cdBig.classList.remove('tick');
        void cdBig.offsetWidth;
        cdBig.classList.add('tick');
      }
    }
    if (setupCountdownSoundSec !== remaining) {
      setupCountdownSoundSec = remaining;
      void playCountdownTick(remaining);
    }
    if (cdRing) {
      cdRing.style.strokeDasharray = String(ringC);
      cdRing.style.strokeDashoffset = String(ringC * (1 - progressLeft));
    }
    if (cdLine) {
      cdLine.hidden = false;
      cdLine.textContent = `Старт через ${remaining}…`;
    }
    if (hint) {
      hint.textContent = 'Не двигайся';
      hint.className = 'setup-hint ok';
    }
  } else if (locked) {
    if (cdOverlay) cdOverlay.hidden = true;
    if (hint) {
      hint.textContent = 'Бой!';
      hint.className = 'setup-hint ok';
    }
    beginFightFromSetup();
  } else {
    if (cdOverlay) cdOverlay.hidden = true;
    if (cdLine) cdLine.hidden = true;
    if (hint) {
      hint.textContent = result.hint;
      hint.className = `setup-hint ${result.ready ? '' : 'warn'}`;
    }
  }
}

async function startSetup(): Promise<void> {
  document.getElementById('btn-back')?.addEventListener('click', () => goHome());
  try {
    wireSoundToggle();
  } catch {
    /* sound UI must not block camera */
  }

  const video = document.querySelector<HTMLVideoElement>('#cam');
  if (!video) return;

  try {
    setBootMsg('Запрос доступа к камере…');
    if (!isCameraAlive()) {
      stream = await navigator.mediaDevices.getUserMedia(VIDEO_CONSTRAINTS);
      cameraReady = true;
    }
    // Drop overlay ASAP — preview bind must not block the UI.
    dismissBootOverlay();
    await bindCameraToVideo(video);
    void RepDetector.warmUp().catch(() => undefined);

    const hint = document.getElementById('setup-hint');
    if (hint && !RepDetector.isModelReady()) {
      hint.textContent = 'Загрузка модели позы…';
      hint.className = 'setup-hint warn';
    }

    const canvas = document.querySelector<HTMLCanvasElement>('#pose-canvas');
    detector = new RepDetector({
      exercise: selectedExercise,
      mode: 'setup',
      onRep: () => undefined,
      onPhase: () => undefined,
      onPose: (found) => {
        poseFound = found;
      },
      onSetup: (result) => updateSetupUi(result)
    });
    await detector.init();
    detector.reset();
    detector.start(video, canvas);
    if (hint && hint.textContent === 'Загрузка модели позы…') {
      hint.textContent = 'Прими стартовую позу';
      hint.className = 'setup-hint';
    }
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    const boot = document.getElementById('boot-overlay');
    if (boot) {
      setBootMsg(message);
    } else {
      const hintEl = document.getElementById('setup-hint');
      if (hintEl) {
        hintEl.textContent = message;
        hintEl.className = 'setup-hint warn';
      }
    }
  }
}

function waveLabel(level: Level, index: number, foe: Foe): string {
  const n = index + 1;
  const total = level.foes.length;
  return foe.kind === 'boss' ? `БОСС · ${n}/${total}` : `Моб ${n}/${total}`;
}

