function updateFightStatus(): void {
  const status = document.getElementById('status-line');
  const debugEl = document.getElementById('pose-debug');
  const ex = currentExercise();
  if (!status) return;
  status.className = 'status-line';
  if (debugEl) {
    if (selectedExercise === 'pushup' && lastDebugLine) {
      debugEl.hidden = false;
      debugEl.textContent = lastDebugLine;
    } else {
      debugEl.hidden = true;
      debugEl.textContent = '';
    }
  }
  if (!poseFound) {
    status.textContent = 'Встань/ляг в кадр — должны появиться точки';
    status.classList.add('warn');
    return;
  }
  if (selectedExercise === 'pushup') {
    if (phase === 'down') {
      status.textContent = lastHint.includes('Не засчитано')
        ? lastHint
        : lastHint || 'Низ ✓ — выжми вверх';
      status.classList.add(lastHint.includes('Не засчитано') ? 'warn' : 'ok');
    } else if (phase === 'up') {
      status.textContent = lastHint || 'Верх ✓ — опустись';
      if (lastHint.includes('упор') || lastHint.includes('Отодвинься')) {
        status.classList.add('warn');
      }
    } else status.textContent = lastHint || 'Согни локти';
  } else if (selectedExercise === 'crunch') {
    if (phase === 'down') {
      status.textContent = 'Скручен ✓ — ляг обратно';
      status.classList.add('ok');
    } else status.textContent = lastHint || 'Скручивай корпус';
  } else if (phase === 'down') {
    status.textContent = 'Низ ✓ — вверх';
    status.classList.add('ok');
  } else status.textContent = lastHint || ex.short;
}

function bindPushupStrictnessControls(): void {
  document.querySelectorAll<HTMLButtonElement>('[data-strict]').forEach((btn) => {
    btn.addEventListener('click', () => {
      const next = btn.dataset.strict as PushupStrictness;
      if (next !== 'normal' && next !== 'strict') return;
      pushupStrictness = next;
      try {
        localStorage.setItem('moveboss-pushup-strictness', next);
      } catch {
        /* ignore */
      }
      detector?.setPushupStrictness(next);
      document.querySelectorAll<HTMLButtonElement>('[data-strict]').forEach((b) => {
        b.classList.toggle('active', b.dataset.strict === next);
      });
    });
  });
}

function updateArenaHud(foe: Foe): void {
  const remaining = Math.max(0, foe.hp - damage);
  const pct = remaining / foe.hp;
  const hpFill = document.getElementById('hp-fill');
  const hpCount = document.getElementById('hp-count');
  const repCount = document.getElementById('rep-count');
  const bossBig = document.getElementById('boss-big');
  if (hpFill) hpFill.style.transform = `scaleX(${pct})`;
  if (hpCount) hpCount.textContent = String(remaining);
  if (repCount) repCount.textContent = String(damage);
  updateFightStatus();
  if (bossBig && remaining <= 0) bossBig.classList.add('dead');
}

function updateChallengeHud(challenge: Challenge): void {
  const left = Math.max(0, challenge.targetReps - damage);
  const pct = Math.max(0, 1 - damage / challenge.targetReps);
  const hpFill = document.getElementById('hp-fill');
  const hpCount = document.getElementById('hp-count');
  const repCount = document.getElementById('rep-count');
  const timerEl = document.getElementById('challenge-timer');
  const bossBig = document.getElementById('boss-big');
  if (hpFill) hpFill.style.transform = `scaleX(${pct})`;
  if (hpCount) hpCount.textContent = String(left);
  if (repCount) repCount.textContent = String(damage);
  if (timerEl && challengeEndsAt) {
    const msLeft = Math.max(0, challengeEndsAt - Date.now());
    timerEl.textContent = `Время: ${formatChallengeTime(msLeft)}`;
    timerEl.classList.toggle('timer-urgent', msLeft <= 15000);
  }
  updateFightStatus();
  if (bossBig && damage >= challenge.targetReps) bossBig.classList.add('dead');
}

function flashHit(): void {
  const bossBig = document.getElementById('boss-big');
  if (!bossBig) return;
  bossBig.classList.remove('hit');
  void bossBig.offsetWidth;
  bossBig.classList.add('hit');
  lastHitAt = Date.now();
  window.setTimeout(() => {
    if (Date.now() - lastHitAt >= 140) bossBig.classList.remove('hit');
  }, 160);
}

function onFoeDefeated(foe: Foe): void {
  stopDetectorOnly();
  if (!activeLevel) return;
  const isLast = foeIndex >= activeLevel.foes.length - 1;
  if (isLast || foe.kind === 'boss') {
    lastClearTotalReps = levelTotalHp(activeLevel);
    markLevelCleared(activeLevel.id, lastClearTotalReps, selectedExercise);
    screen = 'victory';
    render();
    return;
  }
  screen = 'wave';
  render();
}

function finishChallenge(won: boolean): void {
  if (screen !== 'fight' || playMode !== 'challenge' || !activeChallenge) return;
  clearChallengeTimer();
  stopDetectorOnly();
  challengeWon = won;
  lastChallengeTimeMs = Date.now() - challengeStartedAt;
  if (won) {
    markChallengeBest(
      activeChallenge.id,
      lastChallengeTimeMs,
      activeChallenge.targetReps,
      selectedExercise
    );
  }
  screen = 'challengeResult';
  render();
}

async function attachCameraAndDetector(
  onRep: (total: number) => void
): Promise<boolean> {
  const bootMsg = document.getElementById('boot-msg');
  const video = document.querySelector<HTMLVideoElement>('#cam');
  if (!video) return false;

  if (RepDetector.isModelReady()) dismissBootOverlay();

  try {
    if (!isCameraAlive()) {
      setBootMsg('Запрашиваем доступ к камере…');
      if (stream) {
        stream.getTracks().forEach((t) => t.stop());
        stream = null;
      }
      stream = await navigator.mediaDevices.getUserMedia(VIDEO_CONSTRAINTS);
      cameraReady = true;
    }
    dismissBootOverlay();
    await bindCameraToVideo(video);

    if (!RepDetector.isModelReady()) {
      const status = document.getElementById('status-line');
      if (status) {
        status.textContent = 'Загрузка модели позы…';
        status.className = 'status-line warn';
      }
    }

    const canvas = document.querySelector<HTMLCanvasElement>('#pose-canvas');
    detector = new RepDetector({
      exercise: selectedExercise,
      mode: 'fight',
      pushupStrictness,
      onRep,
      onPhase: (p, info) => {
        phase = p;
        lastHint = info.hint;
        lastDebugLine = info.debugLine ?? '';
        if (playMode === 'challenge' && activeChallenge) updateChallengeHud(activeChallenge);
        else if (activeLevel) updateArenaHud(currentFoe());
      },
      onPose: (found) => {
        poseFound = found;
        if (playMode === 'challenge' && activeChallenge) updateChallengeHud(activeChallenge);
        else if (activeLevel) updateArenaHud(currentFoe());
      }
    });
    await detector.init();
    detector.reset();
    detector.start(video, canvas);
    bindPushupStrictnessControls();
    dismissBootOverlay();
    return true;
  } catch (err) {
    cameraReady = false;
    const name = err instanceof DOMException ? err.name : '';
    const message = err instanceof Error ? err.message : String(err);
    let text = message;
    if (name === 'NotAllowedError' || name === 'PermissionDeniedError') {
      text = 'Камера запрещена. Назад → «Разрешить камеру».';
    }
    if (bootMsg) bootMsg.textContent = text;
    else {
      const status = document.getElementById('status-line');
      if (status) {
        status.textContent = text;
        status.className = 'status-line warn';
      }
    }
    return false;
  }
}

async function startFight(foe: Foe): Promise<void> {
  document.getElementById('btn-back')?.addEventListener('click', () => goHome());
  try {
    wireSoundToggle();
  } catch {
    /* ignore */
  }
  const ok = await attachCameraAndDetector((total) => {
    damage = Math.min(foe.hp, total);
    void playRepBeep();
    flashHit();
    updateArenaHud(foe);
    if (damage >= foe.hp) onFoeDefeated(foe);
  });
  if (ok) updateArenaHud(foe);
}

async function startChallengeFight(challenge: Challenge): Promise<void> {
  document.getElementById('btn-back')?.addEventListener('click', () => {
    clearChallengeTimer();
    goHome();
  });
  try {
    wireSoundToggle();
  } catch {
    /* ignore */
  }

  const ok = await attachCameraAndDetector((total) => {
    if (screen !== 'fight') return;
    damage = Math.min(challenge.targetReps, total);
    void playRepBeep();
    flashHit();
    updateChallengeHud(challenge);
    if (damage >= challenge.targetReps) finishChallenge(true);
  });
  if (!ok) return;

  challengeStartedAt = Date.now();
  challengeEndsAt = challengeStartedAt + challenge.timeLimitSec * 1000;
  updateChallengeHud(challenge);
  clearChallengeTimer();
  challengeTimerId = window.setInterval(() => {
    if (screen !== 'fight' || playMode !== 'challenge') {
      clearChallengeTimer();
      return;
    }
    updateChallengeHud(challenge);
    if (Date.now() >= challengeEndsAt) finishChallenge(false);
  }, 200);
}

