/**
 * Скручивания полубоком: подъём плеч выше таза.
 *
 * Прямые / согнутые ноги — разные пороги (как у push-up slow/fast каналы).
 * Колено в угол не входит — только shoulder↔hip.
 */
export type CrunchLm = { x: number; y: number; visibility?: number };

export type CrunchArmMode = 'chest' | 'head' | 'swing' | 'unknown';

export interface CrunchFlatBaseline {
  /** hip.y - shoulder.y лёжа (часто ~0) */
  lift: number;
  /** угол подъёма торса лёжа, ° */
  elevDeg: number;
  torsoLen: number;
}

export interface CrunchPoseEval {
  oriented: boolean;
  /** 0..1 curl для UI / фильтров */
  curl: number;
  /** Сырой подъём: hip.y - shoulder.y (плечи выше таза → больше) */
  lift: number;
  /** Подъём минус flat baseline */
  liftDelta: number;
  /** Угол торса к горизонту, ° */
  elevDeg: number;
  elevDelta: number;
  torsoOk: boolean;
  kneesBent: boolean;
  hipsStable: boolean;
  landmarkOk: boolean;
  armMode: CrunchArmMode;
  isSitUpLike: boolean;
  torsoLen: number;
  hint: string;
  failReason: string | null;
  /** для совместимости HUD */
  angle: number;
}

/** Hysteresis на сглаженном curl */
export const CRUNCH_PEAK_ENTER = 0.5;
export const CRUNCH_FLAT_ENTER = 0.2;

/** Прямые ноги — амплитуда обычно больше */
export const CRUNCH_STRAIGHT_LIFT_MIN = 0.045;
export const CRUNCH_STRAIGHT_LIFT_PEAK = 0.09;
export const CRUNCH_STRAIGHT_ELEV_MIN = 14;
export const CRUNCH_STRAIGHT_ELEV_PEAK = 32;

/** Согнутые — плечи поднимаются меньше */
export const CRUNCH_BENT_LIFT_MIN = 0.03;
export const CRUNCH_BENT_LIFT_PEAK = 0.065;
export const CRUNCH_BENT_ELEV_MIN = 10;
export const CRUNCH_BENT_ELEV_PEAK = 24;

function mid(a: CrunchLm, b: CrunchLm): { x: number; y: number } {
  return { x: (a.x + b.x) / 2, y: (a.y + b.y) / 2 };
}

function jointAngle(a: CrunchLm, b: CrunchLm, c: CrunchLm): number {
  const radians =
    Math.atan2(c.y - b.y, c.x - b.x) - Math.atan2(a.y - b.y, a.x - b.x);
  let angle = Math.abs((radians * 180) / Math.PI);
  if (angle > 180) angle = 360 - angle;
  return angle;
}

function clamp01(v: number): number {
  return Math.min(1, Math.max(0, v));
}

function vis(lm: CrunchLm[], i: number): number {
  return lm[i]?.visibility ?? 1;
}

function dist2d(a: { x: number; y: number }, b: { x: number; y: number }): number {
  return Math.hypot(a.x - b.x, a.y - b.y);
}

/**
 * Угол подъёма плеч над тазом: 0° = плоско, растёт когда shoulder.y < hip.y.
 * (y вниз в кадре → плечи «выше» = меньший y)
 */
export function torsoElevDeg(
  shoulder: { x: number; y: number },
  hip: { x: number; y: number }
): number {
  const dx = Math.abs(shoulder.x - hip.x);
  const lift = hip.y - shoulder.y; // >0 если плечи выше таза в кадре
  return (Math.atan2(Math.max(0, lift), Math.max(0.02, dx)) * 180) / Math.PI;
}

export function crunchHalfSideOriented(lm: CrunchLm[]): boolean {
  const shoulder = mid(lm[11], lm[12]);
  const hip = mid(lm[23], lm[24]);
  const knee = mid(lm[25], lm[26]);
  const ankle = mid(lm[27], lm[28]);

  const alongX = Math.max(
    Math.abs(shoulder.x - ankle.x),
    Math.abs(shoulder.x - knee.x),
    Math.abs(hip.x - knee.x),
    Math.abs(shoulder.x - hip.x)
  );
  const torsoDrop = hip.y - shoulder.y;
  const lyingFlatish = Math.abs(torsoDrop) < 0.38;
  const bodyAlongFrame = alongX > 0.14;
  const standing =
    torsoDrop > 0.25 &&
    (ankle.y - shoulder.y > 0.42 || knee.y - shoulder.y > 0.35);

  return lyingFlatish && bodyAlongFrame && !standing;
}

export function crunchFeetTowardCamera(lm: CrunchLm[]): boolean {
  return crunchHalfSideOriented(lm);
}

export function detectCrunchArmMode(
  lm: CrunchLm[],
  wristSpeed: number = 0
): CrunchArmMode {
  if (wristSpeed >= 0.55) return 'swing';

  const nose = lm[0];
  const lEar = lm[7];
  const rEar = lm[8];
  const lWrist = lm[15];
  const rWrist = lm[16];
  const midChest = mid(lm[11], lm[12]);
  if (!(vis(lm, 15) > 0.18 || vis(lm, 16) > 0.18)) return 'unknown';

  const headAnchor = mid(
    vis(lm, 7) > 0.12 ? lEar : nose,
    vis(lm, 8) > 0.12 ? rEar : nose
  );
  const nearHead =
    (vis(lm, 15) > 0.18 && dist2d(lWrist, headAnchor) < 0.2) ||
    (vis(lm, 16) > 0.18 && dist2d(rWrist, headAnchor) < 0.2);
  if (nearHead) return 'head';

  const onChest =
    (vis(lm, 15) > 0.18 &&
      Math.abs(lWrist.y - midChest.y) < 0.16 &&
      Math.abs(lWrist.x - midChest.x) < 0.25) ||
    (vis(lm, 16) > 0.18 &&
      Math.abs(rWrist.y - midChest.y) < 0.16 &&
      Math.abs(rWrist.x - midChest.x) < 0.25);
  if (onChest) return 'chest';
  return 'unknown';
}

export function evaluateCrunchPose(
  lm: CrunchLm[],
  baseline: CrunchFlatBaseline = { lift: 0, elevDeg: 4, torsoLen: 0.28 },
  wristSpeed: number = 0
): CrunchPoseEval {
  const shoulder = mid(lm[11], lm[12]);
  const hip = mid(lm[23], lm[24]);

  const oriented = crunchHalfSideOriented(lm);
  const armMode = detectCrunchArmMode(lm, wristSpeed);

  const kneesOk = vis(lm, 25) > 0.15 || vis(lm, 26) > 0.15;
  const hipsOk = vis(lm, 23) > 0.15 || vis(lm, 24) > 0.15;
  const shouldersOk = vis(lm, 11) > 0.15 || vis(lm, 12) > 0.15;
  const landmarkOk = oriented && hipsOk && shouldersOk;

  const leftKnee = jointAngle(lm[23], lm[25], lm[27]);
  const rightKnee = jointAngle(lm[24], lm[26], lm[28]);
  const kneeAngle = Math.min(leftKnee, rightKnee);
  const kneesBent = kneesOk && kneeAngle < 155;

  // Главный сигнал: плечи выше таза в кадре
  const lift = hip.y - shoulder.y;
  const elevDeg = torsoElevDeg(shoulder, hip);
  const torsoLen = Math.max(0.08, dist2d(shoulder, hip));

  const liftDelta = lift - baseline.lift;
  const elevDelta = Math.max(0, elevDeg - baseline.elevDeg);

  const liftMin = kneesBent ? CRUNCH_BENT_LIFT_MIN : CRUNCH_STRAIGHT_LIFT_MIN;
  const liftPeak = kneesBent ? CRUNCH_BENT_LIFT_PEAK : CRUNCH_STRAIGHT_LIFT_PEAK;
  const elevMin = kneesBent ? CRUNCH_BENT_ELEV_MIN : CRUNCH_STRAIGHT_ELEV_MIN;
  const elevPeak = kneesBent ? CRUNCH_BENT_ELEV_PEAK : CRUNCH_STRAIGHT_ELEV_PEAK;

  const liftCurl = clamp01(liftDelta / liftPeak);
  const elevCurl = clamp01(elevDelta / elevPeak);
  // Оба прокси про плечи↔таз — без колена
  let curl = clamp01(0.55 * liftCurl + 0.45 * elevCurl);
  if (armMode === 'swing') curl *= 0.7;

  const liftOk = liftDelta >= liftMin;
  const elevOk = elevDelta >= elevMin;
  const torsoOk = liftOk && elevOk;

  // Таз стабилен
  const hipsStable = hip.y > 0.15 && hip.y < 0.92;
  if (!hipsStable) curl *= 0.85;

  const isSitUpLike = elevDelta >= elevPeak * 1.35 || liftDelta >= liftPeak * 1.4;

  let failReason: string | null = null;
  let hint: string;
  if (!oriented) {
    failReason = 'orient';
    hint = 'Ляг полубоком — плечи и таз в кадре';
  } else if (!landmarkOk) {
    failReason = 'landmarks';
    hint = 'Плечи и таз в кадре';
  } else if (!hipsStable) {
    failReason = 'hips';
    hint = 'Таз на полу';
  } else if (armMode === 'swing') {
    failReason = 'arms';
    hint = 'Без инерции руками';
  } else if (curl >= CRUNCH_PEAK_ENTER && torsoOk) {
    failReason = null;
    hint = 'Скручен ✓ — ляг обратно';
  } else if (curl <= CRUNCH_FLAT_ENTER) {
    failReason = null;
    hint = 'Лёжа ✓ — подними плечи выше таза';
  } else if (!liftOk) {
    failReason = 'torso';
    hint = `Выше плечи · подъём ${(liftDelta * 100).toFixed(0)}%`;
  } else if (!elevOk) {
    failReason = 'torso';
    hint = `Выше · угол ${Math.round(elevDelta)}° / ${elevMin}°`;
  } else {
    failReason = 'mid';
    hint = 'Доведи подъём или опускание';
  }

  return {
    oriented,
    curl,
    lift,
    liftDelta,
    elevDeg,
    elevDelta,
    torsoOk,
    kneesBent,
    hipsStable,
    landmarkOk,
    armMode,
    isSitUpLike,
    torsoLen,
    hint,
    failReason,
    angle: elevDeg
  };
}
