/**
 * Camera preview with correct aspect ratio (no stretch).
 * Uses cover: scale to fill .video-wrap, crop overflow. Painted via canvas
 * because mobile browsers mishandle object-fit on <video>.
 */

export type VideoCoverLayout = {
  ox: number;
  oy: number;
  dw: number;
  dh: number;
};

export function computeVideoCoverLayout(
  videoW: number,
  videoH: number,
  boxW: number,
  boxH: number
): VideoCoverLayout {
  const scale = Math.max(boxW / Math.max(1, videoW), boxH / Math.max(1, videoH));
  const dw = videoW * scale;
  const dh = videoH * scale;
  return {
    ox: (boxW - dw) / 2,
    oy: (boxH - dh) / 2,
    dw,
    dh
  };
}

export function mapNormToCover(
  nx: number,
  ny: number,
  layout: VideoCoverLayout
): { x: number; y: number } {
  return {
    x: layout.ox + nx * layout.dw,
    y: layout.oy + ny * layout.dh
  };
}

let raf = 0;
let running = false;
let observedVideo: HTMLVideoElement | null = null;
let preview: HTMLCanvasElement | null = null;
let observer: ResizeObserver | null = null;

function ensurePreviewCanvas(wrap: HTMLElement): HTMLCanvasElement {
  let canvas = wrap.querySelector<HTMLCanvasElement>('#cam-preview');
  if (!canvas) {
    canvas = document.createElement('canvas');
    canvas.id = 'cam-preview';
    canvas.className = 'cam-preview';
    canvas.setAttribute('aria-hidden', 'true');
    const pose = wrap.querySelector('#pose-canvas');
    if (pose) wrap.insertBefore(canvas, pose);
    else wrap.appendChild(canvas);
  }
  preview = canvas;
  return canvas;
}

function hideSourceVideo(video: HTMLVideoElement): void {
  video.style.position = 'absolute';
  video.style.left = '0';
  video.style.top = '0';
  video.style.width = '1px';
  video.style.height = '1px';
  video.style.opacity = '0';
  video.style.pointerEvents = 'none';
  video.style.zIndex = '-1';
  video.removeAttribute('width');
  video.removeAttribute('height');
}

function paintFrame(video: HTMLVideoElement, canvas: HTMLCanvasElement, wrap: HTMLElement): void {
  const cssW = Math.max(1, Math.round(wrap.clientWidth));
  const cssH = Math.max(1, Math.round(wrap.clientHeight));
  const dpr = Math.min(2.5, Math.max(1, window.devicePixelRatio || 1));
  const bw = Math.round(cssW * dpr);
  const bh = Math.round(cssH * dpr);
  if (canvas.width !== bw || canvas.height !== bh) {
    canvas.width = bw;
    canvas.height = bh;
  }
  canvas.style.width = `${cssW}px`;
  canvas.style.height = `${cssH}px`;

  const ctx = canvas.getContext('2d');
  if (!ctx) return;
  ctx.setTransform(1, 0, 0, 1, 0, 0);
  ctx.fillStyle = '#111';
  ctx.fillRect(0, 0, bw, bh);
  if (video.readyState < 2 || video.videoWidth < 2 || video.videoHeight < 2) return;

  const layout = computeVideoCoverLayout(video.videoWidth, video.videoHeight, cssW, cssH);
  ctx.drawImage(
    video,
    layout.ox * dpr,
    layout.oy * dpr,
    layout.dw * dpr,
    layout.dh * dpr
  );
}

function tick(): void {
  if (!running || !observedVideo || !preview) return;
  const wrap = observedVideo.closest('.video-wrap') as HTMLElement | null;
  if (wrap) paintFrame(observedVideo, preview, wrap);
  raf = requestAnimationFrame(tick);
}

export function applyVideoSqueeze(video: HTMLVideoElement): void {
  const wrap = video.closest('.video-wrap') as HTMLElement | null;
  if (!wrap) return;
  hideSourceVideo(video);
  const canvas = ensurePreviewCanvas(wrap);
  paintFrame(video, canvas, wrap);
}

export function bindVideoSqueeze(video: HTMLVideoElement): void {
  const wrap = video.closest('.video-wrap') as HTMLElement | null;
  if (!wrap) return;

  observedVideo = video;
  hideSourceVideo(video);
  ensurePreviewCanvas(wrap);
  applyVideoSqueeze(video);

  observer?.disconnect();
  if (typeof ResizeObserver !== 'undefined') {
    observer = new ResizeObserver(() => applyVideoSqueeze(video));
    observer.observe(wrap);
  }

  if (!running) {
    running = true;
    cancelAnimationFrame(raf);
    raf = requestAnimationFrame(tick);
  }

  const onMeta = () => applyVideoSqueeze(video);
  video.addEventListener('loadedmetadata', onMeta);
  video.addEventListener('playing', onMeta);
  requestAnimationFrame(() => applyVideoSqueeze(video));
  window.setTimeout(() => applyVideoSqueeze(video), 80);
  window.setTimeout(() => applyVideoSqueeze(video), 300);
}

export function unbindVideoSqueeze(): void {
  running = false;
  cancelAnimationFrame(raf);
  raf = 0;
  observer?.disconnect();
  observer = null;
  observedVideo = null;
  preview = null;
}
