/** Контент арен «Легион Силы» — без БД, всё в коде. */

export type FoeKind = 'mob' | 'boss';

export interface Foe {
  id: string;
  name: string;
  kind: FoeKind;
  hp: number;
  emoji: string;
  color: string;
  blurb: string;
}

export type LevelId =
  | 'recruit'
  | 'legionnaire'
  | 'gladiator'
  | 'centurion'
  | 'titan'
  | 'emperor';

export interface Level {
  id: LevelId;
  name: string;
  title: string;
  emoji: string;
  color: string;
  /** Короткий лор арены */
  lore: string;
  blurb: string;
  /** Знамя за прохождение */
  banner: string;
  foes: Foe[];
}

function L(
  id: string,
  name: string,
  kind: FoeKind,
  hp: number,
  emoji: string,
  color: string,
  blurb: string
): Foe {
  return { id, name: `Легионер «${name}»`, kind, hp, emoji, color, blurb };
}

