export function getLevel(id: LevelId): Level {
  const level = LEVELS.find((l) => l.id === id);
  if (!level) throw new Error(`Unknown level: ${id}`);
  return level;
}

export function levelTotalHp(level: Level): number {
  return level.foes.reduce((sum, f) => sum + f.hp, 0);
}

export function levelMobCount(level: Level): number {
  return level.foes.filter((f) => f.kind === 'mob').length;
}

export function getFoe(level: Level, index: number): Foe {
  const foe = level.foes[index];
  if (!foe) throw new Error(`No foe at index ${index}`);
  return foe;
}
