/**
 * Face-on push-up signals (phone on floor, athlete looking into camera).
 *
 * Primary cues for this angle (not side-view):
 * - 3D/world elbow angle (2D collapses into depth)
 * - best-arm by visibility
 * - upper-arm horizontal (shoulder ≈ elbow height, elbow out)
 * - shoulder–wrist distance cycle
 * - hip–shoulder–elbow “plank” shoulder angle
 */

export type PushupLm = { x: number; y: number; z?: number; visibility?: number };

export interface PushupPoseEval {
  inPlank: boolean;
  bodyHorizontal: boolean;
  bodyStraight: boolean;
  keyPointsVisible: boolean;
  handsPosition: boolean;
  /** Straighter arm (lockout) — prefers 3D / best visibility */
  armAngleUp: number;
  /** More bent arm (valley) — prefers 3D / best visibility */
  armAngleDown: number;
  elbowDrop: number;
  leftElbowY: number;
  rightElbowY: number;
  elbowWidth: number;
  elbowLateral: number;
  /** elbowWidth / shoulderWidth — face-on ROM proxy */
  flareRatio: number;
  shoulderWidth: number;
  /** shoulder–hip–(ankle|knee) line angle; null-ish via bodyLineKnown */
  bodyLineAngle: number;
  /** Soft: true if unknown or roughly straight */
  bodyLineOk: boolean;
  bodyLineKnown: boolean;
  /** Primary face-on depth: upper arm near-horizontal and/or classic cues */
  elbowAtDepth: boolean;
  /** hip–shoulder–elbow angle (plank vs standing arm-wave) */
  shoulderAngle: number;
  /** 2D shoulder↔wrist distance (shrinks when lowering toward camera) */
  shoulderWristDist: number;
  /** At least one upper arm is near-horizontal (depth landmark) */
  upperArmHorizontal: boolean;
  /** Per-arm elbow angles (3D blend), for symmetry checks */
  leftArmAngle: number;
  rightArmAngle: number;
  leftArmOk: boolean;
  rightArmOk: boolean;
  leftWristX: number;
  leftWristY: number;
  rightWristX: number;
  rightWristY: number;
  /** Clear pike/sag — hard form fail */
  bodyLineHardFail: boolean;
  isStanding: boolean;
  hintSetup: string;
  hintFight: string;
  failPlankReason: string | null;
  /** Athlete filled too much of the frame — step back */
  tooClose: boolean;
}

function mid(a: PushupLm, b: PushupLm): { x: number; y: number; z: number } {
  return {
    x: (a.x + b.x) / 2,
    y: (a.y + b.y) / 2,
    z: ((a.z ?? 0) + (b.z ?? 0)) / 2
  };
}

/** 2D joint angle (image plane). */
export function jointAngle(a: PushupLm, b: PushupLm, c: PushupLm): number {
  const radians =
    Math.atan2(c.y - b.y, c.x - b.x) - Math.atan2(a.y - b.y, a.x - b.x);
  let angle = Math.abs((radians * 180) / Math.PI);
  if (angle > 180) angle = 360 - angle;
  return angle;
}

/** 3D joint angle from world (or image+z) landmarks — better for face-on. */
export function jointAngle3D(a: PushupLm, b: PushupLm, c: PushupLm): number {
  const bax = a.x - b.x;
  const bay = a.y - b.y;
  const baz = (a.z ?? 0) - (b.z ?? 0);
  const bcx = c.x - b.x;
  const bcy = c.y - b.y;
  const bcz = (c.z ?? 0) - (b.z ?? 0);
  const magBa = Math.hypot(bax, bay, baz);
  const magBc = Math.hypot(bcx, bcy, bcz);
  if (magBa < 1e-6 || magBc < 1e-6) return 180;
  const cos = Math.min(1, Math.max(-1, (bax * bcx + bay * bcy + baz * bcz) / (magBa * magBc)));
  return (Math.acos(cos) * 180) / Math.PI;
}

function vis(lm: PushupLm[], i: number): number {
  return lm[i]?.visibility ?? 1;
}

function dist2d(a: PushupLm, b: PushupLm): number {
  return Math.hypot(a.x - b.x, a.y - b.y);
}

export const GOUP_UP_ANGLE = 105;
/** Relative ROM from personal lockout top — reject tiny wobbles, keep real reps. */
export const GOUP_MIN_BEND_FROM_TOP = 17;
export const GOUP_MIN_RISE_FROM_BOTTOM = 10;
export const GOUP_MIN_FRAMES_BETWEEN = 4;
export const GOUP_MIN_ELBOW_DROP = 0.02;
export const GOUP_UP_ELBOW_DROP_MAX = 0.2;
export const GOUP_MIN_DOWN_FRAMES = 2;
/** Kept for compatibility; single-path counter no longer uses a dual fast channel. */
export const GOUP_FAST_MIN_BEND = 12;
export const GOUP_FAST_MIN_RISE = 8;
export const GOUP_FAST_MIN_DOWN_FRAMES = 2;
export const GOUP_FAST_SWING = 20;
export const GOUP_MIN_ELBOW_DESCENT = 0.022;
export const GOUP_ELBOW_SHOULDER_DY_MAX = 0.11;
export const GOUP_ELBOW_WRIST_DY_MAX = 0.18;
export const GOUP_MIN_ELBOW_FLARE = 0.016;
export const GOUP_MIN_ELBOW_LATERAL_GAIN = 0.012;
export const GOUP_MIN_FLARE_RATIO_GAIN = 0.03;
export const GOUP_BODY_LINE_MIN = 145;
export const GOUP_BODY_LINE_MAX = 205;
/** Clear pike/sag — advisory only in rep machine. */
export const GOUP_BODY_LINE_HARD_MIN = 138;
export const GOUP_BODY_LINE_HARD_MAX = 212;
export const GOUP_UPPER_ARM_DY_MAX = 0.09;
export const GOUP_UPPER_ARM_DX_MIN = 0.035;
export const GOUP_MIN_SHOULDER_WRIST_SHRINK = 0.018;
/** Hip–shoulder–elbow: reject near-straight “arms by torso” standing. */
export const GOUP_PLANK_SHOULDER_ANGLE_MAX = 155;
export const GOUP_ARM_VIS_MIN = 0.22;
/** Symmetry: each arm bend from top, or angles stay close. */
export const GOUP_SYM_MIN_BEND = 10;
export const GOUP_SYM_MAX_ANGLE_DELTA = 24;
/** Wrist slide — soft hint / hard abort. */
export const GOUP_WRIST_SHIFT_SOFT = 0.065;
export const GOUP_WRIST_SHIFT_HARD = 0.12;
/** Soft tempo floors (face-on continuous sets). */
export const GOUP_MIN_BOTTOM_MS = 70;
export const GOUP_MIN_DOWN_MS = 180;
/**
 * Soft valley hint only — NOT a hard reject (absolute angles fail across people).
 */
export const GOUP_VALLEY_MAX_ANGLE = 118;
/** Need this many solid 2D proxies (OR model: 1 is enough). */
export const GOUP_MIN_SOLID_PROXIES = 1;

export type PushupStrictness = 'normal' | 'strict';

export interface PushupGates {
  minBend: number;
  minRise: number;
  minProxies: number;
  upAngle: number;
  debounceMs: number;
  lockoutHold: number;
  lockoutGrace: number;
}

/** Tunable presets for live testing with different athletes. */
export function pushupGates(level: PushupStrictness = 'normal'): PushupGates {
  if (level === 'strict') {
    // Between former “strict 22°” (too many skips) and normal 17°.
    return {
      minBend: 20,
      minRise: 11,
      minProxies: 1,
      upAngle: 108,
      debounceMs: 400,
      lockoutHold: 2,
      lockoutGrace: 4
    };
  }
  return {
    minBend: GOUP_MIN_BEND_FROM_TOP,
    minRise: GOUP_MIN_RISE_FROM_BOTTOM,
    minProxies: GOUP_MIN_SOLID_PROXIES,
    upAngle: GOUP_UP_ANGLE,
    debounceMs: 350,
    lockoutHold: 1,
    lockoutGrace: 3
  };
}


export function isUpperArmHorizontal(shoulder: PushupLm, elbow: PushupLm): boolean {
  const dx = Math.abs(elbow.x - shoulder.x);
  const dy = Math.abs(elbow.y - shoulder.y);
  return dy <= GOUP_UPPER_ARM_DY_MAX && dx >= GOUP_UPPER_ARM_DX_MIN;
}

/**
 * One elbow reached depth. Upper-arm horizontal is primary for face-on;
 * shoulder/wrist proximity remains as fallback.
 */
export function armElbowAtDepth(
  shoulder: PushupLm,
  elbow: PushupLm,
  wrist: PushupLm,
  shoulderVis: number,
  elbowVis: number,
  wristVis: number
): boolean {
  if (elbowVis < 0.25) return false;

  if (isUpperArmHorizontal(shoulder, elbow)) return true;

  if (shoulderVis >= 0.28) {
    const atShoulderLevel =
      elbow.y >= shoulder.y - 0.04 &&
      Math.abs(elbow.y - shoulder.y) <= GOUP_ELBOW_SHOULDER_DY_MAX;
    if (atShoulderLevel && Math.abs(elbow.x - shoulder.x) >= GOUP_UPPER_ARM_DX_MIN * 0.7) {
      return true;
    }
  }

  if (wristVis < 0.2) return false;
  return elbow.y >= wrist.y - GOUP_ELBOW_WRIST_DY_MAX;
}

export function pushupElbowWidth(lm: PushupLm[]): number {
  return Math.abs(lm[13].x - lm[14].x);
}

export function pushupElbowLateral(lm: PushupLm[]): number {
  const left = Math.abs(lm[13].x - lm[11].x);
  const right = Math.abs(lm[14].x - lm[12].x);
  return Math.max(left, right);
}

export function pushupShoulderWidth(lm: PushupLm[]): number {
  return Math.abs(lm[11].x - lm[12].x);
}

export function pushupFlareRatio(lm: PushupLm[]): number {
  const sw = Math.max(0.02, pushupShoulderWidth(lm));
  return pushupElbowWidth(lm) / sw;
}

/**
 * Soft torso straightness: shoulder–hip–ankle, else knee, else unknown.
 */
export function computeBodyLine(
  lm: PushupLm[],
  world?: PushupLm[] | null
): { angle: number; ok: boolean; known: boolean } {
  const src = world && world.length > 28 ? world : lm;
  const use3d = Boolean(world && world.length > 28);
  const ang = use3d ? jointAngle3D : jointAngle;

  const leftAnkle = vis(lm, 27) > 0.3;
  const rightAnkle = vis(lm, 28) > 0.3;
  const leftKnee = vis(lm, 25) > 0.3;
  const rightKnee = vis(lm, 26) > 0.3;

  let angle: number | null = null;

  if (leftAnkle && rightAnkle) {
    const a = ang(src[11], src[23], src[27]);
    const b = ang(src[12], src[24], src[28]);
    angle = (a + b) / 2;
  } else if (leftAnkle) {
    angle = ang(src[11], src[23], src[27]);
  } else if (rightAnkle) {
    angle = ang(src[12], src[24], src[28]);
  } else if (leftKnee && rightKnee) {
    const a = ang(src[11], src[23], src[25]);
    const b = ang(src[12], src[24], src[26]);
    angle = (a + b) / 2;
  } else if (leftKnee) {
    angle = ang(src[11], src[23], src[25]);
  } else if (rightKnee) {
    angle = ang(src[12], src[24], src[26]);
  }

  if (angle == null) {
    return { angle: 180, ok: true, known: false };
  }

  const ok = angle >= GOUP_BODY_LINE_MIN && angle <= GOUP_BODY_LINE_MAX;
  return { angle, ok, known: true };
}

function armVisibilityScore(lm: PushupLm[], s: number, e: number, w: number): number {
  return vis(lm, s) + vis(lm, e) + vis(lm, w);
}

/**
 * Elbow angles preferring world/3D landmarks and the more visible arm.
 */
export function computeArmAngles(
  lm: PushupLm[],
  world?: PushupLm[] | null
): {
  armAngleUp: number;
  armAngleDown: number;
  leftArmAngle: number;
  rightArmAngle: number;
  leftOk: boolean;
  rightOk: boolean;
  used3d: boolean;
} {
  const src = world && world.length > 16 ? world : lm;
  const used3d = Boolean(world && world.length > 16);
  const ang = used3d ? jointAngle3D : jointAngle;

  const leftScore = armVisibilityScore(lm, 11, 13, 15);
  const rightScore = armVisibilityScore(lm, 12, 14, 16);
  const leftOk = leftScore >= GOUP_ARM_VIS_MIN * 3;
  const rightOk = rightScore >= GOUP_ARM_VIS_MIN * 3;

  const left2d = jointAngle(lm[11], lm[13], lm[15]);
  const right2d = jointAngle(lm[12], lm[14], lm[16]);
  const left3d = ang(src[11], src[13], src[15]);
  const right3d = ang(src[12], src[14], src[16]);

  // Blend 3D with a bit of 2D for stability when world flickers
  const left = used3d ? 0.75 * left3d + 0.25 * left2d : left2d;
  const right = used3d ? 0.75 * right3d + 0.25 * right2d : right2d;

  let armAngleDown: number;
  let armAngleUp: number;

  if (leftOk && rightOk) {
    // Prefer better-visible arm for the bent signal; keep max for lockout
    if (leftScore >= rightScore + 0.15) {
      armAngleDown = left;
      armAngleUp = Math.max(left, right);
    } else if (rightScore >= leftScore + 0.15) {
      armAngleDown = right;
      armAngleUp = Math.max(left, right);
    } else {
      armAngleDown = (left + right) / 2;
      armAngleUp = Math.max(left, right);
    }
  } else if (leftOk) {
    armAngleDown = left;
    armAngleUp = left;
  } else if (rightOk) {
    armAngleDown = right;
    armAngleUp = right;
  } else {
    armAngleDown = Math.min(left, right);
    armAngleUp = Math.max(left, right);
  }

  return {
    armAngleUp,
    armAngleDown,
    leftArmAngle: left,
    rightArmAngle: right,
    leftOk,
    rightOk,
    used3d
  };
}

/** Both arms bent enough, or angles stay close (symmetric form). */
export function pushupArmsSymmetric(
  topAngle: number,
  leftAngle: number,
  rightAngle: number,
  leftOk: boolean,
  rightOk: boolean
): boolean {
  if (!leftOk || !rightOk) return true; // can't judge — don't block
  const leftBend = topAngle - leftAngle;
  const rightBend = topAngle - rightAngle;
  const bothBent =
    leftBend >= GOUP_SYM_MIN_BEND && rightBend >= GOUP_SYM_MIN_BEND;
  const close = Math.abs(leftAngle - rightAngle) <= GOUP_SYM_MAX_ANGLE_DELTA;
  return bothBent || close;
}

export function evaluatePushupPose(
  lm: PushupLm[],
  worldLm?: PushupLm[] | null
): PushupPoseEval {
  const shoulder = mid(lm[11], lm[12]);
  const hip = mid(lm[23], lm[24]);
  const knee = mid(lm[25], lm[26]);
  const ankle = mid(lm[27], lm[28]);
  const wrist = mid(lm[15], lm[16]);
  const elbow = mid(lm[13], lm[14]);
  const nose = lm[0];

  const elbowsOk = vis(lm, 13) > 0.28 || vis(lm, 14) > 0.28;
  const keyPointsVisible =
    elbowsOk &&
    (vis(lm, 11) > 0.2 || vis(lm, 12) > 0.2) &&
    (vis(lm, 13) > 0.28 || vis(lm, 15) > 0.25) &&
    (vis(lm, 14) > 0.28 || vis(lm, 16) > 0.25);

  const torsoDrop = hip.y - shoulder.y;
  const bodyHorizontal = Math.abs(torsoDrop) < 0.28;

  const anklesVisible = vis(lm, 27) > 0.35 && vis(lm, 28) > 0.35;
  const kneesVisible = vis(lm, 25) > 0.35 && vis(lm, 26) > 0.35;
  const standingFullBody =
    anklesVisible &&
    ankle.y - shoulder.y > 0.4 &&
    (torsoDrop > 0.12 || (kneesVisible && knee.y > hip.y + 0.06));

  const holdingDevice =
    (vis(lm, 15) > 0.25 || vis(lm, 16) > 0.25) &&
    wrist.y < shoulder.y - 0.06 &&
    (!nose || Math.abs(wrist.y - nose.y) < 0.22);

  // Shoulder angle: hip–shoulder–elbow (prefer world if available)
  const w = worldLm && worldLm.length > 24 ? worldLm : lm;
  const use3dSh = Boolean(worldLm && worldLm.length > 24);
  const shAngFn = use3dSh ? jointAngle3D : jointAngle;
  const leftShoulderAng = shAngFn(w[23], w[11], w[13]);
  const rightShoulderAng = shAngFn(w[24], w[12], w[14]);
  const leftShScore = armVisibilityScore(lm, 11, 13, 23);
  const rightShScore = armVisibilityScore(lm, 12, 14, 24);
  const shoulderAngle =
    leftShScore >= rightShScore ? leftShoulderAng : rightShoulderAng;

  // Near-straight shoulder angle while torso upright ≈ standing / not plank arms
  const badShoulderForPlank =
    shoulderAngle > GOUP_PLANK_SHOULDER_ANGLE_MAX && torsoDrop > 0.1;

  const upright =
    torsoDrop > 0.24 || standingFullBody || holdingDevice || badShoulderForPlank;
  const isStanding = upright;

  const handsPosition =
    wrist.y >= shoulder.y - 0.12 && wrist.y <= shoulder.y + 0.45;

  const {
    armAngleUp,
    armAngleDown,
    leftArmAngle,
    rightArmAngle,
    leftOk: leftArmOk,
    rightOk: rightArmOk
  } = computeArmAngles(lm, worldLm);

  const elbowDrop = Math.max(0, elbow.y - shoulder.y);
  const upperArmHorizontal =
    isUpperArmHorizontal(lm[11], lm[13]) || isUpperArmHorizontal(lm[12], lm[14]);
  const elbowAtDepth =
    upperArmHorizontal ||
    armElbowAtDepth(lm[11], lm[13], lm[15], vis(lm, 11), vis(lm, 13), vis(lm, 15)) ||
    armElbowAtDepth(lm[12], lm[14], lm[16], vis(lm, 12), vis(lm, 14), vis(lm, 16));

  const elbowWidth = pushupElbowWidth(lm);
  const elbowLateral = pushupElbowLateral(lm);
  const shoulderWidth = pushupShoulderWidth(lm);
  const flareRatio = pushupFlareRatio(lm);
  const bodyLine = computeBodyLine(lm, worldLm);
  const bodyLineHardFail =
    bodyLine.known &&
    (bodyLine.angle < GOUP_BODY_LINE_HARD_MIN ||
      bodyLine.angle > GOUP_BODY_LINE_HARD_MAX);

  // Mean shoulder↔wrist distance (face-on depth proxy)
  const shoulderWristDist =
    (dist2d(lm[11], lm[15]) + dist2d(lm[12], lm[16])) / 2;

  const tooClose = false;

  const inPlank =
    keyPointsVisible && bodyHorizontal && handsPosition && !isStanding;

  const failPlankReason = !inPlank
    ? isStanding
      ? 'standing'
      : !keyPointsVisible
        ? 'keypoints'
        : !handsPosition
          ? 'hands'
          : 'torso'
    : null;

  const hintSetup = !inPlank
    ? isStanding
      ? 'Упор лёжа — не стой'
      : !keyPointsVisible
        ? 'Локти в кадр'
        : 'Ладони на полу, корпус ровно'
    : 'Готово — не двигайся';

  const hintFight = !inPlank
    ? isStanding
      ? 'Убери телефон с рук — упор лёжа'
      : 'Держи упор лёжа в кадре'
    : upperArmHorizontal
      ? `Низ ✓ · ${Math.round(armAngleDown)}°`
      : `Локти ${Math.round(armAngleDown)}°`;

  return {
    inPlank,
    bodyHorizontal,
    bodyStraight: bodyLine.ok || !bodyLine.known,
    keyPointsVisible,
    handsPosition,
    armAngleUp,
    armAngleDown,
    elbowDrop,
    leftElbowY: lm[13].y,
    rightElbowY: lm[14].y,
    elbowWidth,
    elbowLateral,
    flareRatio,
    shoulderWidth,
    bodyLineAngle: bodyLine.angle,
    bodyLineOk: bodyLine.ok,
    bodyLineKnown: bodyLine.known,
    bodyLineHardFail,
    elbowAtDepth,
    shoulderAngle,
    shoulderWristDist,
    upperArmHorizontal,
    leftArmAngle,
    rightArmAngle,
    leftArmOk,
    rightArmOk,
    leftWristX: lm[15].x,
    leftWristY: lm[15].y,
    rightWristX: lm[16].x,
    rightWristY: lm[16].y,
    isStanding,
    hintSetup,
    hintFight,
    failPlankReason,
    tooClose
  };
}

export function isPushupDownPosition(
  armAngleDown: number,
  elbowDrop: number,
  topAngle: number,
  minBend: number = GOUP_MIN_BEND_FROM_TOP
): boolean {
  const bend = topAngle - armAngleDown;
  return bend >= minBend && elbowDrop >= GOUP_MIN_ELBOW_DROP;
}

export function isPushupUpPosition(armAngleUp: number, elbowDrop: number): boolean {
  return armAngleUp >= GOUP_UP_ANGLE && elbowDrop <= GOUP_UP_ELBOW_DROP_MAX;
}
