/** Прогресс арены в localStorage (без SQL). */

import type { LevelId } from './levels';
import type { ChallengeId } from './challenges';

const KEY = 'legion-arena-progress-v1';

export interface LevelClear {
  clearedAt: string;
  totalReps: number;
  exercise: string;
}

export interface ChallengeBest {
  clearedAt: string;
  /** Время прохождения в мс (меньше = лучше) */
  timeMs: number;
  exercise: string;
  targetReps: number;
}

export interface ArenaProgress {
  levels: Partial<Record<LevelId, LevelClear>>;
  challenges: Partial<Record<ChallengeId, ChallengeBest>>;
}

function empty(): ArenaProgress {
  return { levels: {}, challenges: {} };
}

export function loadProgress(): ArenaProgress {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return empty();
    const parsed = JSON.parse(raw) as ArenaProgress;
    return {
      levels: parsed.levels ?? {},
      challenges: parsed.challenges ?? {}
    };
  } catch {
    return empty();
  }
}

export function saveProgress(progress: ArenaProgress): void {
  localStorage.setItem(KEY, JSON.stringify(progress));
}

export function markLevelCleared(
  levelId: LevelId,
  totalReps: number,
  exercise: string
): ArenaProgress {
  const progress = loadProgress();
  const prev = progress.levels[levelId];
  progress.levels[levelId] = {
    clearedAt: new Date().toISOString(),
    totalReps: prev ? Math.max(prev.totalReps, totalReps) : totalReps,
    exercise
  };
  saveProgress(progress);
  return progress;
}

export function markChallengeBest(
  challengeId: ChallengeId,
  timeMs: number,
  targetReps: number,
  exercise: string
): ArenaProgress {
  const progress = loadProgress();
  const prev = progress.challenges[challengeId];
  if (!prev || timeMs < prev.timeMs) {
    progress.challenges[challengeId] = {
      clearedAt: new Date().toISOString(),
      timeMs,
      targetReps,
      exercise
    };
    saveProgress(progress);
  }
  return progress;
}

export function isLevelCleared(levelId: LevelId): boolean {
  return Boolean(loadProgress().levels[levelId]);
}

export function clearedLevelCount(): number {
  return Object.keys(loadProgress().levels).length;
}
